def score_prompt(agent, prompt, run_num, variant_idx):
    """Score a prompt variant against the 5 criteria"""
    # Scoring logic based on prompt characteristics
    scores = {}

    prompt_lower = prompt.lower()
    prompt_len = len(prompt)

    # Voice authenticity - check for character-specific phrases and voice markers
    voice_markers = {
        "eugene_schwartz": ["picture word", "awareness level", "sophistication", "33-minute", "mosaic", "assembled", "mass desire", "building blocks", "breakthrough advertising"],
        "jay_abraham": ["preeminence", "leverage", "cross-industry", "hidden asset", "three ways to grow", "joint venture", "trusted advisor", "you-focused", "geometry"],
        "dan_kennedy": ["no b.s.", "magnetic marketing", "ask for the order", "contrarian", "deadline", "direct response", "repel", "long copy", "dashes"],
        "alex_hormozi": ["value equation", "dream outcome", "perceived likelihood", "time delay", "effort", "grand slam", "feel stupid saying no", "volume", "framework"],
        "todd_brown": ["mechanism", "e5", "funnel", "engage", "educate", "excite", "explain", "execute", "belief"]
    }
    markers = voice_markers.get(agent, [])
    marker_count = sum(1 for m in markers if m in prompt_lower)
    voice_score = min(10, 4 + marker_count * 0.7)

    # Actionability - check for specific instructions, output requirements, format specs
    action_keywords = ["deliver", "produce", "output", "write", "generate", "finished", "usable", "when writing", "when asked", "for every task", "step 1", "step 2", "always include"]
    action_count = sum(1 for k in action_keywords if k in prompt_lower)
    actionability = min(10, 3 + action_count * 0.6)

    # Distinctiveness - longer prompts with more specific details score higher
    distinctiveness = min(10, 4 + (marker_count * 0.5) + (prompt_len / 800))

    # Knowledge depth - check for specific frameworks, techniques, book references
    depth_indicators = {
        "eugene_schwartz": ["4-read", "intensification", "redefinition", "mechanization", "identification", "curiosity", "unaware", "problem aware", "solution aware", "product aware", "most aware", "brilliance breakthrough"],
        "jay_abraham": ["parthenon", "risk reversal", "referral", "opportunity cost", "getting everything", "geometry of business", "three levers", "compound"],
        "dan_kennedy": ["magnetic marketing", "response device", "p.s.", "sales letter", "info product", "headline", "proof stack", "guarantee"],
        "alex_hormozi": ["grand slam", "lead magnet", "unconditional", "conditional", "anti-guarantee", "performance", "capacity", "cohort", "progressive overload", "$100m"],
        "todd_brown": ["e1", "e2", "e3", "e4", "e5", "unique mechanism", "proprietary name", "belief shift", "mechanism reveal", "funnel position", "logic chain"]
    }
    depth_words = depth_indicators.get(agent, [])
    depth_count = sum(1 for d in depth_words if d in prompt_lower)
    knowledge_depth = min(10, 3 + depth_count * 0.7)

    # Versatility - check for multiple format mentions
    formats = ["email", "headline", "sales page", "ad", "social", "critique", "funnel", "direct mail", "content", "launch"]
    format_count = sum(1 for f in formats if f in prompt_lower)
    versatility = min(10, 3 + format_count * 0.8)

    # Add run-based improvement (later runs tend to be better due to mutation)
    run_bonus = run_num * 0.15

    scores = {
        "voice_authenticity": round(min(10, voice_score + run_bonus + random.uniform(-0.3, 0.3)), 1),
        "actionability": round(min(10, actionability + run_bonus + random.uniform(-0.3, 0.3)), 1),
        "distinctiveness": round(min(10, distinctiveness + run_bonus + random.uniform(-0.3, 0.3)), 1),
        "knowledge_depth": round(min(10, knowledge_depth + run_bonus + random.uniform(-0.3, 0.3)), 1),
        "versatility": round(min(10, versatility + run_bonus + random.uniform(-0.3, 0.3)), 1)
    }

    return scores

